/// <summary>
/// Returns name of address element type
/// </summary>
/// <returns>
/// Name of address element type for current address element
/// </returns>
// <GEERU>
[SysClientCacheDataMethodAttribute(true)]
display AddrTypeName_RU addrTypeName_RU()
{
    return LogisticsAddressProperties_RU::find(this.Properties_RU).addrTypeName();
}

// </GEERU>
/// <summary>
/// Returns name of related city
/// </summary>
/// <returns>
/// Name of related city
/// </returns>
// <GEERU>
[SysClientCacheDataMethodAttribute(true)]
display LogisticsAddressCityName cityName_RU()
{
    return LogisticsAddressCity::getCityName(this.City);
}

// </GEERU>
/// <summary>
/// Finds county for current district
/// </summary>
/// <returns>
/// County record, found by City or by FK
/// </returns>
// <GEERU>
public LogisticsAddressCounty county_RU()
{
    LogisticsAddressCounty   ret;
    LogisticsAddressCity    city;

    if (this.City)
    {
        city = LogisticsAddressCity::find_RU(this.City);
        ret  = LogisticsAddressCounty::find(city.CountryRegionId, city.StateId, city.CountyId);
    }

    return ret ? ret : LogisticsAddressCounty::find(this.CountryRegionId_RU, this.StateId_RU, this.CountyId_RU);
}

// </GEERU>
/// <summary>
/// Returns name of current address element
/// </summary>
/// <returns>
/// Name of current address element concatenated with address element type name
/// </returns>
// <GEERU>
[SysClientCacheDataMethodAttribute(true)]
display Name fullName_RU()
{
    return strRTrim(strRTrim(this.Description) + ' ' + this.addrTypeName_RU());
}

// </GEERU>
/// <summary>
/// Displays or sets code for address element type
/// </summary>
/// <param name="_set">
/// true when editing; false when viewing.
/// </param>
/// <param name="_addrTypeCode">
/// New code for address element type
/// </param>
/// <returns>
/// Code for address element type
/// </returns>
// <GEERU>
[SysClientCacheDataMethodAttribute(true)]
edit AddrTypeCode_RU propertiesAddrTypeCode_RU(
    boolean          _set,
    AddrTypeCode_RU  _addrTypeCode)
{
    AddrTypeCode_RU     ret;
    AddressTypeTable_RU addressTypeTable;

    if (_set)
    {
        addressTypeTable = AddressTypeTable_RU::findByCode(_addrTypeCode);
        ret              = addressTypeTable.AddrTypeCode;
        LogisticsAddressProperties_RU::editAddrTypeCode(true, this, addressTypeTable.RecId);
    }
    else
    {
        ret = AddressTypeTable_RU::find(LogisticsAddressProperties_RU::editAddrTypeCode(false, this, 0)).AddrTypeCode;
    }

    return ret;
}

