/// <summary>
/// Displays or sets ZIP code for address element
/// </summary>
/// <param name="_set">
/// true when editing; false when viewing.
/// </param>
/// <param name="_zipCodeID">
/// New value
/// </param>
/// <returns>
/// Current (edited if _set is true) value
/// </returns>
// <GEERU>
[SysClientCacheDataMethodAttribute(true)]
edit LogisticsAddressZipCodeId propertiesZipCode_RU(
    boolean                   _set,
    LogisticsAddressZipCodeId _zipCodeID)
{
    LogisticsAddressZipCodeId ret;
    LogisticsAddressZipCode   logisticsAddressZipCode;

    if (_set)
    {
        logisticsAddressZipCode = LogisticsAddressZipCode::findZipCodeCountryRegion(_zipCodeID,
                                                                                    this.City                                                 ?
                                                                                    LogisticsAddressCity::find_RU(this.City).CountryRegionId :
                                                                                    this.CountryRegionId_RU);
        ret = logisticsAddressZipCode.ZipCode;
        LogisticsAddressProperties_RU::editZipCode(true, this, logisticsAddressZipCode.RecId);
    }
    else
    {
        ret = LogisticsAddressZipCode::findRecId(LogisticsAddressProperties_RU::editZipCode(false, this, 0)).ZipCode;
    }

    return ret;
}

// </GEERU>
/// <summary>
/// Finds state for current district
/// </summary>
/// <returns>
/// State record, found by City or by FK
/// </returns>
// <GEERU>
public LogisticsAddressState state_RU()
{
    LogisticsAddressState    ret;
    LogisticsAddressCity    city;

    if (this.City)
    {
        city = LogisticsAddressCity::find_RU(this.City);
        ret  = LogisticsAddressState::find(city.CountryRegionId, city.StateId);
    }

    return ret ? ret : LogisticsAddressState::find(this.CountryRegionId_RU, this.StateId_RU);
}

public boolean validateWrite()
{
    boolean ret = super();

    //if (!LogisticsPostalAddressUtility::isCountryRegionRU(this.CountryRegionId_RU) && !this.City)
    //{
    //    ret = checkFailed(strFmt("@SYS26332", fieldPName(ETGLogisticsAddressRuralMuncipalityTable, City)));
    //}
    //else if (this.City)
    //{
    //    ret = ret && this.validateCity();
    //}
    if(this.City)
    {
        ret = ret && this.validateCity();
    }

    return ret;
}

private boolean validateCity()
{
    LogisticsAddressCity city = LogisticsAddressCity::findRecId(this.City);

    boolean isCityStateEmpty = city.StateId == '' &&  this.StateId_RU == '';

    boolean isCityCountyEmpty = city.CountyId == '' && this.CountyId_RU == '';

    boolean isValid = city.CountryRegionId == this.CountryRegionId_RU && city.StateId == this.StateId_RU && city.CountyId == this.CountyId_RU;

    if (!isValid && !(isCityCountyEmpty || isCityStateEmpty))
    {
        return checkFailed(strFmt("@GlobalAddressBook:LogisticsAddressCityNotFoundForStateCountryAndCounty",
            city.CityKey,
            this.CountryRegionId_RU,
            this.StateId_RU,
            this.CountyId_RU));
    }
    else if (!isValid && !isCityStateEmpty)
    {
        return checkFailed(strFmt("@GlobalAddressBook:LogisticsAddressCityNotFoundForStateAndCountry",
            city.CityKey,
            this.CountryRegionId_RU,
            this.StateId_RU));
    }
    else if (!isValid)
    {
        return checkFailed(strFmt("@GlobalAddressBook:LogisticsAddressCityNotFoundForCountryRegion",
            city.CityKey,
            this.CountryRegionId_RU));
    }
    else
    {
        return isValid;
    }
}
